import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.Culc7SYV.js";const g=JSON.parse('{"title":"Grading","description":"","frontmatter":{},"headers":[],"relativePath":"Grading.md","filePath":"Grading.md","lastUpdated":1773806339000}'),d={name:"Grading.md"};function i(n,t,s,l,c,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="grade-logic" tabindex="-1">Grade Logic <a class="header-anchor" href="#grade-logic" aria-label="Permalink to &quot;Grade Logic&quot;">​</a></h2><p>After you reveal a card, you grade recall quality. That grade is passed to FSRS, which updates difficulty and next review timing.</p><h2 id="grade-modes" tabindex="-1">Grade Modes <a class="header-anchor" href="#grade-modes" aria-label="Permalink to &quot;Grade Modes&quot;">​</a></h2><p>LearnKit offers two grading modes, configurable in Settings -&gt; Study -&gt; Grading buttons:</p><h3 id="two-button" tabindex="-1">Two Button <a class="header-anchor" href="#two-button" aria-label="Permalink to &quot;Two Button&quot;">​</a></h3><p>Two-button mode works as a simple pass / fail system:</p><table tabindex="0"><thead><tr><th>Button</th><th>Shortcut</th><th>When to use</th></tr></thead><tbody><tr><td>Again (Fail)</td><td><code>1</code></td><td>Your answer is incorrect, or you couldn&#39;t recall it. If your answer is only partially correct, be strict with yourself — if it would count as wrong in a real-life context, press Again.</td></tr><tr><td>Good (Pass)</td><td><code>2</code></td><td>Your answer is correct.</td></tr></tbody></table><p>This mode is simpler and faster, and is recommended for most users.</p><h3 id="four-button" tabindex="-1">Four Button <a class="header-anchor" href="#four-button" aria-label="Permalink to &quot;Four Button&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Shortcut</th><th>When to use</th></tr></thead><tbody><tr><td>Again</td><td><code>1</code></td><td>Your answer is incorrect or you couldn&#39;t recall it. If your answer is partially correct, be strict with yourself — if it would count as a fail in a real-life context, press Again. You&#39;ll typically use this button about 5–20% of the time.</td></tr><tr><td>Hard</td><td><code>2</code></td><td>Your answer is correct, but you had doubts about it or it took a long time to recall.</td></tr><tr><td>Good</td><td><code>3</code></td><td>Your answer is correct, but it took some mental effort to recall. When used properly, this should be the most commonly used button — roughly 80–95% of the time.</td></tr><tr><td>Easy</td><td><code>4</code></td><td>Your answer is correct and it took no mental effort to recall.</td></tr></tbody></table><p>This mode gives finer control, but it is slower and easier to overthink.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use four buttons only if you want extra grading granularity. Otherwise, keep two-button mode.</p></div><h2 id="auto-graded" tabindex="-1">Auto Graded <a class="header-anchor" href="#auto-graded" aria-label="Permalink to &quot;Auto Graded&quot;">​</a></h2><p>Some card types are graded automatically based on your interaction — you don&#39;t press a separate grade button:</p><table tabindex="0"><thead><tr><th>Card type</th><th>How it&#39;s graded</th></tr></thead><tbody><tr><td><strong>Multiple Choice</strong></td><td>Correct option → Good. Incorrect → Again.</td></tr><tr><td><strong>Ordered Questions</strong></td><td>Correct sequence → Good. Any item wrong → Again.</td></tr></tbody></table><p>For these types, your response applies the grade directly.</p><h2 id="scheduling-impact" tabindex="-1">Scheduling Impact <a class="header-anchor" href="#scheduling-impact" aria-label="Permalink to &quot;Scheduling Impact&quot;">​</a></h2><p>Each grade feeds into the FSRS algorithm, which updates three values for the card:</p><table tabindex="0"><thead><tr><th>Value</th><th>Updated how</th></tr></thead><tbody><tr><td><strong>Stability</strong></td><td>Increases with Good/Easy grades, decreases with Again</td></tr><tr><td><strong>Difficulty</strong></td><td>Increases when you press Again, decreases with Easy</td></tr><tr><td><strong>Next interval</strong></td><td>Calculated so your recall probability equals your target retention on the due date</td></tr></tbody></table><p>See <a href="./Scheduling">Scheduling</a> for a deeper explanation of FSRS.</p><h2 id="key-summary" tabindex="-1">Key Summary <a class="header-anchor" href="#key-summary" aria-label="Permalink to &quot;Key Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Space</code> / <code>Enter</code></td><td>Reveal answer</td></tr><tr><td><code>1</code> – <code>2</code> (two-button)</td><td>Again / Good</td></tr><tr><td><code>1</code> – <code>4</code> (four-button)</td><td>Again / Hard / Good / Easy</td></tr></tbody></table>',24)])])}const b=e(d,[["render",i]]);export{g as __pageData,b as default};
